var projects = build.FindChildrenRecursive<Project>().ToList();
Console.WriteLine("=== PROJECT BUILD RESULTS ===");
foreach (var p in projects)
{
    Console.WriteLine($"{p.Name} -> Succeeded: {p.Succeeded}");
}

Console.WriteLine();
Console.WriteLine("=== ALL ERRORS ===");
var errors = build.FindChildrenRecursive<Error>().ToList();
foreach (var e in errors)
{
    var parent = e.Parent;
    string projectName = "";
    while (parent != null)
    {
        if (parent is Project p) { projectName = p.Name; break; }
        parent = parent.Parent;
    }
    Console.WriteLine($"[{e.Code}] Project={projectName}");
    Console.WriteLine($"  File: {e.File}({e.LineNumber},{e.ColumnNumber})");
    Console.WriteLine($"  Message: {e.Text}");
    Console.WriteLine();
}

// Check for MSB errors
Console.WriteLine("=== MSB MESSAGES (build errors) ===");
var messages = build.FindChildrenRecursive<Message>().Where(m => m.Text != null && m.Text.Contains("MSB")).ToList();
foreach (var m in messages.Take(10))
{
    Console.WriteLine(m.Text);
}
EOF

