using Microsoft.Build.Logging.StructuredLogger;
using System;
using System.Linq;

var build = BinaryLog.ReadBuild("/tmp/sv-1c1ba0f901344d9cb74ba281baeca6be/build.binlog");

// Look for build failure messages in the tree
var allMessages = build.FindChildrenRecursive<Message>().ToList();
var failMessages = allMessages.Where(m => m.Text != null && (m.Text.Contains("did not build") || m.Text.Contains("failed") || m.Text.Contains("not built"))).ToList();
Console.WriteLine("=== FAILURE-RELATED MESSAGES ===");
foreach (var m in failMessages.Take(20))
    Console.WriteLine(m.Text);

// Also look at the CscCommandLineArgs to understand the source
Console.WriteLine();
Console.WriteLine("=== CSC TASKS ===");
var tasks = build.FindChildrenRecursive<Task>().Where(t => t.Name == "Csc").ToList();
foreach (var t in tasks)
{
    var parent = t.Parent;
    string projectName = "";
    while (parent != null)
    {
        if (parent is Project p) { projectName = p.Name; break; }
        parent = parent.Parent;
    }
    var errs = t.FindChildrenRecursive<Error>().Count();
    Console.WriteLine($"Csc in {projectName}: errors={errs}");
}
EOF

