cat > /tmp/binlog-reader/Program.cs << 'EOF'
using Microsoft.Build.Logging.StructuredLogger;
using System;
using System.Linq;

var build = BinaryLog.ReadBuild("/tmp/sv-1c1ba0f901344d9cb74ba281baeca6be/build.binlog");

// Find the source file content from the compiler command line
var tasks = build.FindChildrenRecursive<Task>().Where(t => t.Name == "Csc").ToList();
foreach (var t in tasks)
{
    var parent = t.Parent;
    string projectName = "";
    while (parent != null)
    {
        if (parent is Project p) { projectName = p.Name; break; }
        parent = parent.Parent;
    }
    if (projectName.Contains("Services"))
    {
        Console.WriteLine($"=== Csc task for {projectName} ===");
        var folder = t.FindChildrenRecursive<Folder>().ToList();
        foreach (var f in folder)
            Console.WriteLine($"Folder: {f.Name}");
        var props = t.FindChildrenRecursive<Property>().ToList();
        foreach (var prop in props.Where(p => p.Name == "Sources" || p.Name == "References" || p.Name.Contains("Ref")))
            Console.WriteLine($"  {prop.Name} = {prop.Value}");
        // Get command line args
        var items = t.FindChildrenRecursive<Item>().ToList();
        foreach (var item in items.Take(30))
            Console.WriteLine($"  Item: {item.Name} = {item.Text}");
    }
}
EOF

